/**
 * Stats Heartbeat API
 *
 * POST /api/stats/heartbeat
 * Increments user's total time spent
 */

import { getPayload } from 'payload'
import { z } from 'zod'

import config from '@payload-config'

const heartbeatSchema = z.object({
  seconds: z.number().min(30).max(60),
})

export async function POST(req: Request) {
  const payload = await getPayload({ config })

  // Auth check - return 401 if not authenticated
  const authResult = await payload.auth({ headers: req.headers })
  if (!authResult.user) {
    return Response.json({ error: 'Unauthorized' }, { status: 401 })
  }

  const userId = authResult.user.id

  // Validate request body
  let body: unknown
  try {
    body = await req.json()
  } catch {
    return Response.json({ error: 'Invalid JSON body' }, { status: 400 })
  }

  const validation = heartbeatSchema.safeParse(body)

  if (!validation.success) {
    return Response.json(
      { error: 'Invalid request', details: validation.error.flatten() },
      { status: 400 },
    )
  }

  const { seconds } = validation.data

  // Find or create UserStats for user
  const existingStats = await payload.find({
    collection: 'user-stats',
    where: {
      user: { equals: userId },
    },
    limit: 1,
    overrideAccess: true,
  })

  let statsId: string

  if (existingStats.docs.length > 0) {
    // Update existing stats
    const updated = await payload.update({
      collection: 'user-stats',
      id: existingStats.docs[0].id,
      data: {
        totalTimeSpentSeconds: (existingStats.docs[0].totalTimeSpentSeconds || 0) + seconds,
        lastHeartbeatAt: new Date().toISOString(),
      },
      overrideAccess: true,
    })
    statsId = updated.id as string
  } else {
    // Create new stats
    const created = await payload.create({
      collection: 'user-stats',
      data: {
        user: userId,
        totalTimeSpentSeconds: seconds,
        lastHeartbeatAt: new Date().toISOString(),
        currentStreak: 0,
        longestStreak: 0,
      },
      overrideAccess: true,
    })
    statsId = created.id as string
  }

  // Fetch updated stats to return current total
  const updatedStats = await payload.findByID({
    collection: 'user-stats',
    id: statsId,
    overrideAccess: true,
  })

  return Response.json({
    success: true,
    totalTimeSpentSeconds: updatedStats.totalTimeSpentSeconds,
  })
}

/**
 * Stats Streak API
 *
 * POST /api/stats/streak
 * Updates user's daily streak based on activity
 */

import { getPayload } from 'payload'

import config from '@payload-config'

function getTodayDateString(): string {
  const now = new Date()
  const year = now.getFullYear()
  const month = String(now.getMonth() + 1).padStart(2, '0')
  const day = String(now.getDate()).padStart(2, '0')
  return `${year}-${month}-${day}`
}

function getYesterdayDateString(): string {
  const now = new Date()
  now.setDate(now.getDate() - 1)
  const year = now.getFullYear()
  const month = String(now.getMonth() + 1).padStart(2, '0')
  const day = String(now.getDate()).padStart(2, '0')
  return `${year}-${month}-${day}`
}

export async function POST(req: Request) {
  const payload = await getPayload({ config })

  // Auth check - return 401 if not authenticated
  const authResult = await payload.auth({ headers: req.headers })
  if (!authResult.user) {
    return Response.json({ error: 'Unauthorized' }, { status: 401 })
  }

  const userId = authResult.user.id
  const today = getTodayDateString()
  const yesterday = getYesterdayDateString()

  // Find or create UserStats for user
  const existingStats = await payload.find({
    collection: 'user-stats',
    where: {
      user: { equals: userId },
    },
    limit: 1,
    overrideAccess: true,
  })

  let statsId: string
  let currentStreak: number
  let longestStreak: number

  if (existingStats.docs.length > 0) {
    const stats = existingStats.docs[0]
    statsId = stats.id as string
    const lastActiveDate = stats.lastActiveDate

    // If already counted today, no-op (idempotent)
    if (lastActiveDate === today) {
      return Response.json({
        success: true,
        currentStreak: stats.currentStreak || 0,
        longestStreak: stats.longestStreak || 0,
      })
    }

    // Calculate new streak
    if (lastActiveDate === yesterday) {
      // Consecutive day - increment streak
      currentStreak = (stats.currentStreak || 0) + 1
    } else {
      // Gap in days - reset streak to 1
      currentStreak = 1
    }

    longestStreak = Math.max(stats.longestStreak || 0, currentStreak)

    // Update stats
    await payload.update({
      collection: 'user-stats',
      id: statsId,
      data: {
        currentStreak,
        longestStreak,
        lastActiveDate: today,
      },
      overrideAccess: true,
    })
  } else {
    // First time - create new stats with streak = 1
    currentStreak = 1
    longestStreak = 1

    const created = await payload.create({
      collection: 'user-stats',
      data: {
        user: userId,
        currentStreak,
        longestStreak,
        lastActiveDate: today,
        totalTimeSpentSeconds: 0,
      },
      overrideAccess: true,
    })
    statsId = created.id as string
  }

  return Response.json({
    success: true,
    currentStreak,
    longestStreak,
  })
}

