/**
 * Stats Dashboard Page
 *
 * /stats - Student Statistics Dashboard
 */

import { redirect } from 'next/navigation'

import { getMeUser } from '@/infra/utils/getMeUser'
import { getPayload } from 'payload'
import config from '@payload-config'
import { StatsDashboard } from './_components/StatsDashboard'

interface StatsPageProps {
  searchParams: Promise<{
    courseId?: string
    timeframe?: string
  }>
}

export default async function StatsPage({ searchParams }: StatsPageProps) {
  // Auth gate - redirect to login if not authenticated
  const { user } = await getMeUser({
    nullUserRedirect: '/login',
  })

  if (!user) {
    redirect('/login')
  }

  const params = await searchParams
  const initialCourseId = params.courseId || 'all'
  const initialTimeframe = (params.timeframe as 'week' | 'month' | 'overall') || 'overall'

  // Fetch user's enrolled courses for the filter dropdown
  // For now, return all published courses
  const payload = await getPayload({ config })
  const coursesResult = await payload.find({
    collection: 'courses',
    where: {
      status: { equals: 'published' },
      isActive: { equals: true },
    },
    limit: 100,
    overrideAccess: true,
  })

  const courses = coursesResult.docs.map((course) => ({
    id: course.id,
    title: course.title,
    slug: course.slug,
  }))

  return (
    <div className="container mx-auto px-4 py-8">
      <StatsDashboard
        userId={user.id}
        initialCourseId={initialCourseId}
        initialTimeframe={initialTimeframe}
        courses={courses}
      />
    </div>
  )
}

/**
 * Stats Dashboard Component
 *
 * Main client component for the statistics dashboard
 */

'use client'

import { useEffect, useState } from 'react'

import { useTranslations } from '@/ui/web/providers/I18n'
import { SummaryCards } from './SummaryCards'
import { DashboardFilters } from './DashboardFilters'

interface Course {
  id: string
  title: string
  slug: string
}

interface DashboardData {
  summary: {
    totalProgress: number
    timeSpent: number
    averageScore: number
    dailyStreak: number
  }
  categoryProgress: {
    learn: { count: number }
    practice: { attempted: number; completed: number; successRate: number }
    exams: { averageScore: number }
    ask: { questionsAsked: number; conversations: number }
  }
  topicMastery: Array<{
    chapterId: string
    chapterTitle: string
    successRate: number
  }>
}

interface StatsDashboardProps {
  userId: string
  initialCourseId: string
  initialTimeframe: 'week' | 'month' | 'overall'
  courses: Course[]
}

export function StatsDashboard({
  userId,
  initialCourseId,
  initialTimeframe,
  courses,
}: StatsDashboardProps) {
  const t = useTranslations('stats')
  const [courseId, setCourseId] = useState(initialCourseId)
  const [timeframe, setTimeframe] = useState(initialTimeframe)
  const [data, setData] = useState<DashboardData | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true)
      try {
        const params = new URLSearchParams()
        if (courseId !== 'all') {
          params.set('courseId', courseId)
        }
        params.set('timeframe', timeframe)

        const response = await fetch(`/api/stats/dashboard?${params.toString()}`)
        if (response.ok) {
          const result = await response.json()
          setData(result)
        }
      } catch (error) {
        console.error('Failed to fetch dashboard data:', error)
      } finally {
        setLoading(false)
      }
    }

    fetchData()
  }, [courseId, timeframe])

  return (
    <div className="space-y-6">
      <h1 className="text-3xl font-bold">{t('title')}</h1>

      <DashboardFilters
        courses={courses}
        selectedCourseId={courseId}
        selectedTimeframe={timeframe}
        onCourseChange={setCourseId}
        onTimeframeChange={setTimeframe}
      />

      {loading ? (
        <div className="flex items-center justify-center py-12">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary" />
        </div>
      ) : data ? (
        <SummaryCards summary={data.summary} categoryProgress={data.categoryProgress} />
      ) : (
        <div className="text-center py-12 text-muted-foreground">{t('errorLoading')}</div>
      )}
    </div>
  )
}

/**
 * Summary Cards Component
 *
 * Four summary metric cards for the stats dashboard
 */

'use client'

import { useTranslations } from '@/ui/web/providers/I18n'
import { Card, CardContent, CardHeader, CardTitle } from '@/ui/web/components/card'
import { Flame, Clock, Target, TrendingUp } from 'lucide-react'

interface SummaryData {
  totalProgress: number
  timeSpent: number
  averageScore: number
  dailyStreak: number
}

interface CategoryProgress {
  learn: { count: number }
  practice: { attempted: number; completed: number; successRate: number }
  exams: { averageScore: number }
  ask: { questionsAsked: number; conversations: number }
}

interface SummaryCardsProps {
  summary: SummaryData
  categoryProgress: CategoryProgress
}

function formatTime(seconds: number): string {
  const hours = Math.floor(seconds / 3600)
  const minutes = Math.floor((seconds % 3600) / 60)

  if (hours > 0) {
    return `${hours}h ${minutes}m`
  }
  return `${minutes}m`
}

export function SummaryCards({ summary, categoryProgress }: SummaryCardsProps) {
  const t = useTranslations('stats')

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
      {/* Total Progress */}
      <Card>
        <CardHeader className="pb-2">
          <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
            <Target className="w-4 h-4" />
            {t('totalProgress')}
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="text-3xl font-bold">{summary.totalProgress}%</div>
          <div className="w-full bg-muted rounded-full h-2 mt-2">
            <div
              className="bg-primary h-2 rounded-full transition-all"
              style={{ width: `${summary.totalProgress}%` }}
            />
          </div>
        </CardContent>
      </Card>

      {/* Time Spent */}
      <Card>
        <CardHeader className="pb-2">
          <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
            <Clock className="w-4 h-4" />
            {t('timeSpent')}
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="text-3xl font-bold">{formatTime(summary.timeSpent)}</div>
          <div className="text-sm text-muted-foreground mt-2">
            {t('categoryLearn')}: {categoryProgress.learn.count} {t('lessonsCompleted')}
          </div>
        </CardContent>
      </Card>

      {/* Average Score */}
      <Card>
        <CardHeader className="pb-2">
          <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
            <TrendingUp className="w-4 h-4" />
            {t('averageScore')}
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="text-3xl font-bold">{summary.averageScore}%</div>
          <div className="text-sm text-muted-foreground mt-2">
            {t('categoryPractice')}: {categoryProgress.practice.successRate}% {t('exercisesSuccessful')}
