/**
 * Category Progress Component
 *
 * Displays progress by category using TAB_COLORS
 */

'use client'

import { useTranslations } from '@/ui/web/providers/I18n'
import { Card, CardContent, CardHeader, CardTitle } from '@/ui/web/components/card'
import { TAB_COLORS } from '@/app/(frontend)/courses/[courseSlug]/_components/CourseTabs'
import { GraduationCap, Pencil, FileText, MessageCircle } from 'lucide-react'
import { Progress } from '@/ui/web/components/progress'

interface CategoryProgressData {
  learn: { count: number }
  practice: { attempted: number; completed: number; successRate: number }
  exams: { averageScore: number }
  ask: { questionsAsked: number; conversations: number }
}

interface CategoryProgressProps {
  data: CategoryProgressData
}

export function CategoryProgress({ data }: CategoryProgressProps) {
  const t = useTranslations('stats')

  const categories = [
    {
      key: 'learn',
      icon: GraduationCap,
      color: TAB_COLORS.learn.text,
      title: t('categoryLearn'),
      value: `${data.learn.count} ${t('lessonsCompleted')}`,
      progress: Math.min(data.learn.count * 10, 100), // Approximate progress
    },
    {
      key: 'practice',
      icon: Pencil,
      color: TAB_COLORS.practice.text,
      title: t('categoryPractice'),
      value: `${data.practice.completed}/${data.practice.attempted} (${data.practice.successRate}%) ${t('exercisesSuccessful')}`,
      progress: data.practice.successRate,
    },
    {
      key: 'exams',
      icon: FileText,
      color: TAB_COLORS.exams.text,
      title: t('categoryExams'),
      value: `${t('averageScore')}: ${data.exams.averageScore}%`,
      progress: data.exams.averageScore,
    },
    {
      key: 'ask',
      icon: MessageCircle,
      color: TAB_COLORS.ask.text,
      title: t('categoryAsk'),
      value: `${data.ask.questionsAsked} ${t('questionsAsked')}, ${data.ask.conversations} ${t('conversationsStarted')}`,
      progress: Math.min(data.ask.conversations * 10, 100), // Approximate
    },
  ]

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
      {categories.map((category) => {
        const Icon = category.icon
        return (
          <Card key={category.key}>
            <CardHeader className="pb-2">
              <CardTitle
                className="text-sm font-medium flex items-center gap-2"
                style={{ color: category.color }}
              >
                <Icon className="w-4 h-4" style={{ color: category.color }} />
                {category.title}
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-lg font-semibold">{category.value}</div>
              <Progress
                value={category.progress}
                className="mt-2"
                style={
                  {
                    '--progressforeground': category.color,
                  } as React.CSSProperties
                }
              />
            </CardContent>
          </Card>
        )
      })}
    </div>
  )
}

/**
 * Topic Mastery Component
 *
 * Displays topic/chapter success rates with drill-down capability
 */

'use client'

import { useState } from 'react'

import { useTranslations } from '@/ui/web/providers/I18n'
import { Card, CardContent, CardHeader, CardTitle } from '@/ui/web/components/card'

interface TopicMasteryItem {
  chapterId: string
  chapterTitle: string
  successRate: number
}

interface TopicMasteryProps {
  topics: TopicMasteryItem[]
}

function getSuccessRateColor(rate: number): string {
  if (rate >= 70) return 'text-green-600'
  if (rate >= 40) return 'text-yellow-600'
  return 'text-red-600'
}

export function TopicMastery({ topics }: TopicMasteryProps) {
  const t = useTranslations('stats')
  const [expandedTopic, setExpandedTopic] = useState<string | null>(null)

  if (topics.length === 0) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>{t('topicMastery')}</CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-muted-foreground">{t('noTopics')}</p>
        </CardContent>
      </Card>
    )
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>{t('topicMastery')}</CardTitle>
      </CardHeader>
      <CardContent className="space-y-2">
        {topics.map((topic) => (
          <div key={topic.chapterId}>
            <button
              onClick={() => setExpandedTopic(expandedTopic === topic.chapterId ? null : topic.chapterId)}
              className="w-full flex items-center justify-between p-2 hover:bg-muted rounded-lg transition-colors"
            >
              <span className="font-medium">{topic.chapterTitle}</span>
              <span className={`font-bold ${getSuccessRateColor(topic.successRate)}`}>
                {topic.successRate}%
              </span>
            </button>
            {expandedTopic === topic.chapterId && (
              <div className="mt-2 p-3 bg-muted rounded-lg text-sm">
                <p className="text-muted-foreground">
                  {topic.successRate >= 70
                    ? t('topicMastered')
                    : topic.successRate >= 40
                      ? t('topicImproving')
                      : t('topicNeedsWork')}
                </p>
              </div>
            )}
          </div>
        ))}
      </CardContent>
    </Card>
  )
}

/**
 * Activity Timeline Component
 *
 * Displays recent user activity chronologically
 */

'use client'

import { useEffect, useState } from 'react'

import { useTranslations } from '@/ui/web/providers/I18n'
import { Card, CardContent, CardHeader, CardTitle } from '@/ui/web/components/card'
import { CheckCircle2, FileQuestion, MessageCircle, HelpCircle } from 'lucide-react'

interface Activity {
  actionType: string
  label: string
  targetId: string
  targetCollection: string
  timestamp: string
}

function getActivityIcon(actionType: string) {
  switch (actionType) {
    case 'lesson_completed':
      return <CheckCircle2 className="w-4 h-4 text-green-500" />
    case 'exercise_attempted':
      return <FileQuestion className="w-4 h-4 text-blue-500" />
    case 'exercise_completed':
      return <CheckCircle2 className="w-4 h-4 text-green-600" />
    case 'question_asked':
      return <HelpCircle className="w-4 h-4 text-orange-500" />
    case 'conversation_started':
      return <MessageCircle className="w-4 h-4 text-purple-500" />
    default:
      return <Activity className="w-4 h-4 text-gray-500" />
  }
}

function formatRelativeTime(timestamp: string): string {
  const now = new Date()
  const date = new Date(timestamp)
  const diffMs = now.getTime() - date.getTime()
  const diffMins = Math.floor(diffMs / 60000)
  const diffHours = Math.floor(diffMins / 60)
  const diffDays = Math.floor(diffHours / 24)

  if (diffMins < 1) return 'just now'
  if (diffMins < 60) return `${diffMins}m ago`
  if (diffHours < 24) return `${diffHours}h ago`
  if (diffDays < 7) return `${diffDays}d ago`
  return date.toLocaleDateString()
}

export function ActivityTimeline() {
  const t = useTranslations('stats')
  const [activities, setActivities] = useState<Activity[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    const fetchActivities = async () => {
      try {
        const response = await fetch('/api/stats/activity?limit=10')
        if (response.ok) {
          const data = await response.json()
          setActivities(data.activities || [])
        }
      } catch (error) {
        console.error('Failed to fetch activities:', error)
      } finally {
        setLoading(false)
      }
    }

    fetchActivities()
  }, [])

  if (loading) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>{t('recentActivity')}</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="flex items-center justify-center py-8">
            <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-primary" />
          </div>
        </CardContent>
      </Card>
    )
  }

  if (activities.length === 0) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>{t('recentActivity')}</CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-muted-foreground text-center py-4">{t('noActivity')}</p>
        </CardContent>
      </Card>
    )
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>{t('recentActivity')}</CardTitle>
      </CardHeader>
      <CardContent>
        <div className="space-y-3">
          {activities.map((activity, index) => (
            <div key={`${activity.targetId}-${index}`} className="flex items-start gap-3">
              {getActivityIcon(activity.actionType)}
              <div className="flex-1">
                <p className="text-sm font-medium">{activity.label}</p>
                <p className="text-xs text-muted-foreground">
                  {formatRelativeTime(activity.timestamp)}
                </p>
              </div>
            </div>
          ))}
        </div>
      </CardContent>
    </Card>
  )
}

