/**
 * Activity Logging Hook
 *
 * Reusable hook factory for logging user activities to UserStats
 */

import type { CollectionConfig } from 'payload'

import type { User } from '@/payload-types'

type ActionType =
  | 'lesson_completed'
  | 'exercise_attempted'
  | 'exercise_completed'
  | 'question_asked'
  | 'conversation_started'

interface LogActivityOptions {
  collection: CollectionConfig
}

interface ActivityEntry {
  actionType: ActionType
  label: string
  targetId: string
  targetCollection: string
  timestamp: string
}

export function createLogActivityHook({ collection }: LogActivityOptions) {
  return async function logActivityHook({
    req,
    operation,
    doc,
    previousDoc,
    context,
  }: {
    req: {
      payload: {
        find: (options: {
          collection: string
          where: Record<string, unknown>
          limit?: number
          overrideAccess?: boolean
        }) => Promise<{ docs: Array<{ id: string; activityLog?: ActivityEntry[] }> }>
        update: (options: {
          collection: string
          id: string
          data: Record<string, unknown>
          overrideAccess?: boolean
        }) => Promise<{ id: string | unknown }>
      }
      user?: User | null
    }
    operation: 'create' | 'update' | 'delete'
    doc: Record<string, unknown>
    previousDoc?: Record<string, unknown>
    context?: Record<string, unknown>
  }) {
    // Skip if context flag is set (prevent infinite loops)
    if (context?.skipActivityLog) {
      return doc
    }

    // Only log on create or update
    if (operation !== 'create' && operation !== 'update') {
      return doc
    }

    const user = req?.user
    if (!user?.id) {
      return doc
    }

    // Determine action type based on collection
    let actionType: ActionType | null = null
    let targetId = ''
    let label = ''

    switch (collection.slug) {
      case 'user-progress':
        // Check if a progress record was completed
        if (operation === 'update') {
          const prevRecords = (previousDoc as { progressRecords?: Array<{ recordId: string; status?: string }> })?.progressRecords || []
          const newRecords = (doc as { progressRecords?: Array<{ recordId: string; status?: string; recordType?: string }> })?.progressRecords || []

          // Find records that changed to completed
          for (const newRecord of newRecords) {
            const prevRecord = prevRecords.find((r) => r.recordId === newRecord.recordId)
            if (prevRecord?.status !== 'completed' && newRecord.status === 'completed') {
              targetId = newRecord.recordId
              actionType = newRecord.recordType === 'exercise' ? 'exercise_completed' : 'lesson_completed'
              label = newRecord.recordType === 'exercise' ? 'Completed an exercise' : 'Completed a lesson'
              break
            }
          }
        }
        break

      case 'conversations':
        if (operation === 'create') {
          actionType = 'conversation_started'
          targetId = doc.id as string
          const contextRef = doc.contextRef as { relationTo?: string; value?: string }
          label = `Started a conversation about ${contextRef?.relationTo || 'learning'}`
        }
        break

      default:
        break
    }

    if (!actionType || !targetId) {
      return doc
    }

    // Find or update UserStats
    try {
      const userStatsResult = await req.payload.find({
        collection: 'user-stats',
        where: { user: { equals: user.id } },
        limit: 1,
        overrideAccess: true,
      })

      const activityEntry: ActivityEntry = {
        actionType,
        label,
        targetId,
        targetCollection: collection.slug,
        timestamp: new Date().toISOString(),
      }

      if (userStatsResult.docs.length > 0) {
        const stats = userStatsResult.docs[0]
        const currentLog = (stats.activityLog as ActivityEntry[]) || []
        const updatedLog = [activityEntry, ...currentLog].slice(0, 50) // Keep max 50

        await req.payload.update({
          collection: 'user-stats',
          id: stats.id,
          data: { activityLog: updatedLog },
          overrideAccess: true,
        })
      } else {
        // Create new UserStats with activity
        await req.payload.create({
          collection: 'user-stats',
          data: {
            user: user.id,
            activityLog: [activityEntry],
            totalTimeSpentSeconds: 0,
            currentStreak: 0,
            longestStreak: 0,
          },
          overrideAccess: true,
        })
      }
    } catch (error) {
      console.error('Failed to log activity:', error)
    }

    return doc
  }
}

/**
 * Activity Logging Utility
 *
 * Helper to log user activities to UserStats collection
 */

interface ActivityEntry {
  actionType:
    | 'lesson_completed'
    | 'exercise_attempted'
    | 'exercise_completed'
    | 'question_asked'
    | 'conversation_started'
  label: string
  targetId: string
  targetCollection: string
  timestamp: string
}

interface LogActivityParams {
  payload: {
    find: (options: {
      collection: string
      where: Record<string, unknown>
      limit?: number
      overrideAccess?: boolean
    }) => Promise<{ docs: Array<{ id: string; activityLog?: ActivityEntry[] }> }>
    update: (options: {
      collection: string
      id: string
      data: Record<string, unknown>
      overrideAccess?: boolean
    }) => Promise<{ id: string | unknown }>
    create: (options: {
      collection: string
      data: Record<string, unknown>
      overrideAccess?: boolean
    }) => Promise<{ id: string | unknown }>
  }
  userId: string
  actionType: ActivityEntry['actionType']
  label: string
  targetId: string
  targetCollection: string
}

export async function logActivity({
  payload,
  userId,
  actionType,
  label,
  targetId,
  targetCollection,
}: LogActivityParams): Promise<void> {
  const activityEntry: ActivityEntry = {
    actionType,
    label,
    targetId,
    targetCollection,
    timestamp: new Date().toISOString(),
  }

  try {
    const userStatsResult = await payload.find({
      collection: 'user-stats',
      where: { user: { equals: userId } },
      limit: 1,
      overrideAccess: true,
    })

    if (userStatsResult.docs.length > 0) {
      const stats = userStatsResult.docs[0]
      const currentLog = (stats.activityLog as ActivityEntry[]) || []
      const updatedLog = [activityEntry, ...currentLog].slice(0, 50) // Keep max 50

      await payload.update({
        collection: 'user-stats',
        id: stats.id,
        data: { activityLog: updatedLog },
        overrideAccess: true,
      })
    } else {
      // Create new UserStats with activity
      await payload.create({
        collection: 'user-stats',
        data: {
          user: userId,
          activityLog: [activityEntry],
          totalTimeSpentSeconds: 0,
          currentStreak: 0,
          longestStreak: 0,
        },
        overrideAccess: true,
      })
    }
  } catch (error) {
    console.error('Failed to log activity:', error)
  }
}

